import{_ as i,o as n,c as t,ag as r}from"./chunks/framework.DXGyWiRo.js";const l="/images/lekt2004.jpg",a="/images/lekt2005.jpg",s="/images/lekt2001.jpg",o="/images/lekt2006.jpg",u="/images/lekt2007.jpg",d="/images/lekt2002.jpg",h="/images/lekt2008.jpg",p="/images/lekt2010.jpg",m="/images/lekt2009.jpg",b="/images/lekt2003.jpg",B=JSON.parse('{"title":"Lektion 20","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion20.md","filePath":"lektionen/lektion20.md"}'),c={name:"lektionen/lektion20.md"};function g(k,e,q,v,f,w){return n(),t("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-20" tabindex="-1">Lektion 20 <a class="header-anchor" href="#lektion-20" aria-label="Permalink to &quot;Lektion 20&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>20.1. Possesivkomposita = बहुव्रीहि m.</li><li>20.2. Bahuvrīhi mit attributivem Vorderglied</li><li>20.3. Bahuvrīhi mit appositionellem Vorderglied</li><li>20.4. Bahuvrīhi mit kasuellem Vorderglied</li><li>20.5. Bahuvrīhi mit adverbiellem Vorderglied</li><li>20.6. Flexion des Schlussglieds eines Bahuvrīhi</li><li>20.7. Eine andere Einteilung der Arten von Bahuvrīhis</li><li>20.8. Verhältnis von Bahuvrīhi und Relativsatz</li><li>20.9. Wortliste</li><li>20.10. Übung 1</li><li>20.11. Übung 2</li><li>20.12. Übersetzungsübung</li></ul><h2 id="_20-1-possesivkomposita-बहुव्रीहि-m" tabindex="-1">20.1. Possesivkomposita = बहुव्रीहि m. <a class="header-anchor" href="#_20-1-possesivkomposita-बहुव्रीहि-m" aria-label="Permalink to &quot;20.1. Possesivkomposita = बहुव्रीहि m.&quot;">​</a></h2><p><img src="'+l+'" alt=""><br> Abb.: बहुव्रीहिः पुरुषः<br> Jodhpur = जोधपुर<br> [Bildquelle: Jared Zimmerman. -- <a href="http://www.flickr.com/photos/spoinknet/35414570/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/spoinknet/35414570/</a>. -- Zugriff am 2008-12-11. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>बहुव्रीहिः = बहवो व्रीहयो यस्य सः = &quot;einer, der viel Reis besitzt&quot;</p><p>Ein Bahuvrīhi bezeichnet im Unterschied zum Tatpurua etwas anderes, als durch seine Glieder ausgedrückt wird: während बालपुत्रः als Tatpuruṣa aufgelöst &quot;ein junger Sohn&quot; bedeutet, also etwas, das durch das Schlussglied des Kompositums (पुत्र) ausgedrückt wird, bedeutet बालपुत्रः als Bahuvrīhi aufgelöst &quot;einer, dessen Sohn jung ist&quot;, d.h. das Bezeichnete ist weder der Sohn (पुत्र) noch unbedingt jung (बाल), sondern eine vom jungen Sohn verschiedene Person, nämlich sein Vater.</p><p>Possesivkomposita sind zunächst immer Adjektive, die allerdings substantiviert werden können. Deshalb hängt das grammatische Geschlecht eine Bahuvrīhi von dem ab, worauf sich das Bahuvrīhi bezieht, und nicht von Geschlecht des letzten Kompositionsgliedes.</p><p>Schema für die Auflösung eines Bahuvrīhi:</p><p>1. Glied meist im Nominativ (प्रथमा) Sing., Dual oder Plural -- 2. Glied im Nominativ Sing., Dual oder Plural -- Relativpronomen in einem anderesn Kasus als Nominativ (meist Genetiv - षष्ठी) und in Geschlecht und Zahl des Gesamtbahuvrīhi -- Demonstrativpronomen in Zahl, Fall und Geschlecht des Gesamtbahuvrīhi.</p><p>Beispiele:</p><blockquote><p>गतपापः = गतं पापं यस्य सः = &quot;einer, dessen Böses gegangen ist&quot; = &quot;einer, der frei von Übeltaten ist&quot;</p><blockquote><p>Akk. sg. गतपापम् =  गतं पापं यस्य तम्</p><p>Inst. sg. गतपापेन = गतं पापं यस्य तेन</p><p>Gen. sg. गतपापस्य = गतं पापं यस्य तस्य</p><p>Nom. pl. गतपापाः = गतानि पापानि येषां ते</p><p>usw.</p></blockquote><p>अस्तमोहा = अस्तो मोहो यया सा = &quot;eine (Frau), die die Verblendung abgeworfen hat&quot;</p><p>प्राप्तोदको ग्रामः = प्राप्तमुदकं यं स ग्रामः = &quot;Ein Dorf, an das das Wasser herangekommen ist&quot; = &quot;ein von der Überschwemmung bedrohtes Dorf&quot;</p><p>पुण्यवत्पुत्रः als Bahuvrīhi = पुण्य्अवान्पुत्रो यस्य सः, oder: पुण्यवन्तः पुत्रा यस्य सः = &quot;einer, dessen Sohn Verdienst besitzt&quot; oder: &quot;einer, dessen Söhne Verdienst besitzen&quot;</p></blockquote><p>Das Verhältnis von Vorderglied zu Hinterglied kann bei einem Bahuvrīhi sein:</p><ul><li>attributiv</li><li>appositionell</li><li>kasuell</li><li>adverbial</li></ul><p>Wie beim Tatpuruṣa steht das näher bestimmte Glied meist an zweiter Stelle.</p><p>Traditionell unterscheidet man:</p><ul><li><p>समानाधिकरणबहुव्रीहिः : in विग्रहवाक्य stehen Vorderglied und Hinterglied im selben Kasus</p></li><li><p>व्यधिकरणबहुव्रीहिः : in विग्रहवाक्य stehen Vorderglied und Hinterglied in verschiedenen Kasus</p></li></ul><h2 id="_20-2-bahuvrihi-mit-attributivem-vorderglied" tabindex="-1">20.2. Bahuvrīhi mit attributivem Vorderglied <a class="header-anchor" href="#_20-2-bahuvrihi-mit-attributivem-vorderglied" aria-label="Permalink to &quot;20.2. Bahuvrīhi mit attributivem Vorderglied&quot;">​</a></h2><p>| Schema: Adjektiv -- Nomen</p><p>Beispiel:</p><blockquote><p>गुणवत्पुत्रो ब्राह्मणः =  गुण्वान्पुत्रो यस्य स ब्राह्मणाः = &quot;ein Brahmane, dessen Sohn / Söhne gute Eigenschaften besitzt / besitzen&quot;</p></blockquote><p>| | --- | | Besonders häufig ist die -- bei Tatpuruṣa seltene -- Attributivbestimmung durch ein PPP. Das Relativpronomen steht dann bei der Auflösung meist im Instrumentalis (तृतीया) (seltener im Genetiv / षष्ठी).</p><p>Faustregel:</p><ul><li>PPP - Substantiv = meistens Bahuvrīhi</li><li>Substantiv -- PPP = meistens Tatpuruṣa</li></ul><p>Beispiel:</p><blockquote><p>कृतफल 3 = कृतं फलं येन सः । यया सा । येन तत् = &quot;einer / eine /eines, der / die /das ein Ergebnis hervorgebracht hat, jemand / etwas effektives&quot;</p></blockquote><p>|</p><h2 id="_20-3-bahuvrihi-mit-appositionellem-vorderglied" tabindex="-1">20.3. Bahuvrīhi mit appositionellem Vorderglied <a class="header-anchor" href="#_20-3-bahuvrihi-mit-appositionellem-vorderglied" aria-label="Permalink to &quot;20.3. Bahuvrīhi mit appositionellem Vorderglied&quot;">​</a></h2><p>Schema:</p><p>Substantiv -- Substantiv</p><p>Beispiele:</p><blockquote><p>शूरपुत्रो नरः = शूरा एव पुत्रा यस्य स नरः = &quot;ein Mann, dessen Söhne Helden Sind&quot;</p><p>तदन्त ३ = सो ऽन्तो यस्य सः । यस्याः सा । यस्य तत् = &quot;der / die / das, dessen Ende dieses ist&quot; = &quot;damit endender&quot;</p></blockquote><p>| Sehr wichtig sind appositionelle Bahuvrīhi mit den Endgliedern आदि । आदिक । आद्य &quot;erster, Anfang&quot;,  seltener प्रभृति &quot;Anfang&quot;. Solche Komposita entsprechen dem &quot;u.s.w.&quot;: Beispiel:</p><blockquote><p>देवा इन्द्रादयः = इन्द्र आदिर्येषां ते देवाः = &quot;Die Götter, deren Anfang Indra ist&quot; = &quot;die Götter Indra u.s.w.&quot; = &quot;Indra und die übrigen Götter&quot;</p></blockquote><p>| | --- | | Zum Ausdruck von &quot;nur&quot; kann man bahuvrīhis mit मात्रा f. &quot;Maß, Begrenzung&quot; als Hinterglied verwenden:</p><p>Beispiel:</p><blockquote><p>शब्दमात्रम् = शब्दो मात्रा यस्य तत् = &quot;das, dessen Maß ein Wort ist&quot; = &quot;nur ein Wort&quot;</p></blockquote><p>मात्र nach einem PPP ist mit &quot;sobald als&quot; zu übersetzen:</p><p>Beispiel:</p><blockquote><p>जातमात्रं शत्रुं घ्नन्ति = जातं मात्रा यस्य तं शत्रुं घ्नन्ति = &quot;sie erschlagen einen Feind, dessen Maß das Entstehen ist&quot; = &quot;sie erschlagen den feind, sobald er entstanden ist&quot;</p></blockquote><p>|</p><p><img src="'+a+'" alt=""><br> Abb.: देवा येस्वादयः = Jesus und die übrigen Götter<br> Ahmedabad<br> [Bildquelle: von ganuullu. -- <a href="http://www.flickr.com/photos/ganuullu/373131240/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/ganuullu/373131240/</a>. -- Zugriff am 2008-12-11. --  <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h2 id="_20-4-bahuvrihi-mit-kasuellem-vorderglied" tabindex="-1">20.4. Bahuvrīhi mit kasuellem Vorderglied <a class="header-anchor" href="#_20-4-bahuvrihi-mit-kasuellem-vorderglied" aria-label="Permalink to &quot;20.4. Bahuvrīhi mit kasuellem Vorderglied&quot;">​</a></h2><p>d.h. Bahuvrīhi, deren Vorderglied einen anderen Kasus als den Nominativ (प्रथमा) vertritt.</p><p>Beispiel:</p><blockquote><p>देवरूपा = देवस्यैव रूपं यस्याः सा = &quot;eine (Frau), deren gestalt die eines Gottes ist&quot; &quot;eine Frau von göttlichem Aussehen&quot;</p></blockquote><p>Ausnahme zur allgemeinen Regel über die Reihenfolge der Kompositionsglieder:</p><p>Das kasuelle Glied steht an zweiter Stelle, wenn es einen Körperteil (bes. die Hand) bezeichnet:</p><p>Beispiel:</p><blockquote><p>दण्डहस्तः =  दण्डो हस्ते (Lok. sg.) यस्य सः = &quot;einer, in dessen Hand sich ein Stock befindet&quot; = &quot;einer, der einen Stock in der Hand trägt.&quot;</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: इन्द्रो वज्रपाणिः = पानौ (Lok. sg.) वज्रो यस्य स इन्द्रः = Indra, in dessen Hand sich ein Donnerkeil befindet = Indra mit dem Donnerkeil in der Hand<br> Siemreap (ក្រុងសៀមរាប), Kambodscha, 9. Jhdt n. Chr.<br> [Bildquelle: Wikipedia, Public domain]</p><h2 id="_20-5-bahuvrihi-mit-adverbiellem-vorderglied" tabindex="-1">20.5. Bahuvrīhi mit adverbiellem Vorderglied <a class="header-anchor" href="#_20-5-bahuvrihi-mit-adverbiellem-vorderglied" aria-label="Permalink to &quot;20.5. Bahuvrīhi mit adverbiellem Vorderglied&quot;">​</a></h2><p>Im Vorderglied steht ein Adverb, eine Präposition, ein Präverb oder ein anderes Indeklinabile; solche Komposita sind in der Regel नित्यसमास.</p><p>Beispiele:</p><blockquote><p>अपुत्रो नरः = पुत्रो यस्य नास्ति स नरः = &quot;ein Mann, der keinen Sohn hat&quot; = &quot;ein sohnloser Mann&quot;</p><p>दुर्बल ३ = &quot;jemand / etwas, dessen Kraft schlecht ist&quot; = &quot;kraftlos, schwach&quot;</p></blockquote><p>सह &quot;mit&quot; als Vorderglied eines Bahuvrīhi wird oft durch स ersetzt.</p><p>Beispiel:</p><blockquote><p>सपुत्रः = सहपुत्रः = पुत्रेण सहितः । पुत्रेण सह् = &quot;mit einem Sohn&quot;, &quot;von einem Sohn begleitet&quot;</p></blockquote><p><img src="'+o+'" alt=""><br> Abb.: सपुत्रा<br> Madhya Pradesh<br> [Bildquelle: dhyanji. -- <a href="http://www.flickr.com/photos/dhyanji/147056147/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/dhyanji/147056147/</a>. -- Zugriff am 2008-12-11. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h2 id="_20-6-flexion-des-schlussglieds-eines-bahuvrihi" tabindex="-1">20.6. Flexion des Schlussglieds eines Bahuvrīhi <a class="header-anchor" href="#_20-6-flexion-des-schlussglieds-eines-bahuvrihi" aria-label="Permalink to &quot;20.6. Flexion des Schlussglieds eines Bahuvrīhi&quot;">​</a></h2><p>Das Schlussglied eines Bahuvrīhi wird unabhängig von seinem ursprünglichen Geschlecht als mehrgeschlechtliches Adjektiv flektiert. Hat also in einem Kompositum das Schlussglied einanderes als sein ursprüngliches Geschlecht, so muss es ein Bahuvrīhi sein, wenn es kein Samāhāradvanva (Neutrum sing.) ist.</p><p>Bei der Adjektivierung werden</p><ul><li>-ā-Stämme im Maskulinum und Neutrum zu -a-Stämmen</li><li>-a-Stämme (m., n.) bilden ihr Femininum auf -ā oder -ī</li><li>-ī-Stämme (f.) müssen am Ende von bahuvrīhis das Suffix -ka, -kā, -ka (n.) annehmen; dieses Suffix können bzw. müssen auch viele andere Bahuvrīhi annehmen</li></ul><h2 id="_20-7-eine-andere-einteilung-der-arten-von-bahuvrihis" tabindex="-1">20.7. Eine andere Einteilung der Arten von Bahuvrīhis <a class="header-anchor" href="#_20-7-eine-andere-einteilung-der-arten-von-bahuvrihis" aria-label="Permalink to &quot;20.7. Eine andere Einteilung der Arten von Bahuvrīhis&quot;">​</a></h2><p>Die Beispiele sind hier zur späteren Durcharbeitung gegeben, für einige sind bisher die nötige Grammatik und der Wortschatz noch nicht besprochen</p><ol><li>qualifizierendes Wort im Vorderglied -- qualifiziertes Wort im Hinterglied: स्थिरचित्तः = स्तिरं चित्तं यस्य सः</li><li>Indeklinabile im Vorderglied: उच्चैःश्रवस्</li><li>Vergleich im Vorderglied: कुशाग्रधीः =  कुशाग्र इव धीर्यस्य सः</li><li>Impliziter Vergleich: उष्ट्रमुखः = उष्ट्रस्य मुखमिव मुखं यस्य सः = &quot;kamelmündig&quot; = dessen Mund wie der eines Kamels ist</li><li>Numerale als Hinterglied bei ungefährer Zahl:. उपसशाः = दशानां समीपे ये सन्ति ते = &quot;ungefähr zehn&quot;</li><li>beide Glieder sind Numeralia: एकद्वाः = एको वा द्वौ वा = &quot;ein oder zwei&quot;</li><li>mit sa-/saha- im Vorderglied: सपुत्रः । सहपुत्रः</li><li>mit sa- (= समान) im Vorderglied: सजनपदः = समानो जनपदो यस्य सः</li><li>नञ्बहुव्रीहिः = mit a-/an- im Vorderglied: अपुत्रः = न विद्यते पुत्रो यस्य सः ; अनङ्गः = न विद्यते अङ्गं यस्य सः</li><li>mit Präposition u.ä. im Vorderglied: प्रवातः =प्रकृष्टो वातो यस्मिन् सः ; निर्धनः = निर्गतं धनं यस्मात्सः ; सुबुद्धिः = सुष्ठु बुद्धिर्यस्य सः ; दुर्बुद्धिः = दुष्टा बुद्धिर्यस्य सः</li><li>Richtungsbezeichnungen um Zwischenrichtungen zu bezeichnen: पुर्वोत्तरा &quot;nordöstlich&quot;</li><li>PPP als Vorderglied: कृतकटः = कृतः कटो येन सः</li><li>und andere</li></ol><p><img src="'+u+'" alt=""><br> Abb.: कृतकटा (कट m. &quot;Matte&quot;)<br> Chennai = சென்னை<br> [Bildquelle: calamur. -- <a href="http://www.flickr.com/photos/gargi/162477734/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/gargi/162477734/</a>. -- Zugriff am 2008-12-11. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h2 id="_20-8-verhaltnis-von-bahuvrihi-und-relativsatz" tabindex="-1">20.8. Verhältnis von Bahuvrīhi und Relativsatz <a class="header-anchor" href="#_20-8-verhaltnis-von-bahuvrihi-und-relativsatz" aria-label="Permalink to &quot;20.8. Verhältnis von Bahuvrīhi und Relativsatz&quot;">​</a></h2><p>Obwohl jedes Bahuvrīhi durch einen Relativsatz aufgelöst wird, kann nicht jeder Relativsatz durch ein Bahuvrīhi ersetzt werden. Hermann Georg Jacobi (1850 - 1937), der das Verhältnis beider näher untersucht hat (Compositum und Nebensatz, 1897), schreibt:</p><blockquote><p>&quot;Wenn man aus dem Deutschen oder einer anderen modernen Sprache ins Sanskrit übersetzt, dürfen nicht alle Nebensätze durch Composita wiedergegeben werden, sondern nur die ausschmückenden und beschreibenden; diejenigen aber, welche eine begrifflich notwendige oder wichtige Bestimmung enthalten, erscheinen auch im Sanskrit als Relativsätze.&quot;</p></blockquote><p><img src="'+d+'" alt=""><br> Abb.: Hermann Jacobi<br> [Bildquelle: Beiträge zur Literaturwissenschaft und Geistesgeschichte Indiens. -- Bonn, 1926]</p><p>Das mag stimmen. Allerdings sehen dann die Inder vieles als ausschmückend und beschreibend an, was wir als &quot;begrifflich notwendig oder wichtig&quot; ansehen würden.</p><h2 id="_20-9-wortliste" tabindex="-1">20.9. Wortliste <a class="header-anchor" href="#_20-9-wortliste" aria-label="Permalink to &quot;20.9. Wortliste&quot;">​</a></h2><p>वा : oder</p><p>आश्रम m., n.: Einsiedelei, Lebensstadium, Lebensabschnitt (nämlich als ब्रह्मचरिन्, गृहस्त, वनप्रस्थ und evtl. als सन्न्यासिन् ; siehe Basham, Wonder S. 159f.)</p><p><img src="'+h+'" alt=""><br> Abb.: आश्रमाः<br> Rishikesh = ऋषिकेश<br> [Bildquelle: von ogimogi. -- <a href="http://www.flickr.com/photos/ogimogi/284517677/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/ogimogi/284517677/</a>. -- Zugriff am 2008-12-11. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung)]</p><blockquote><p>&quot;This is actually part of the Ashram in Rishikesh where the Beatles stayed. This specific part was not there when they were there, but it does look cool.&quot;</p></blockquote><p>कर ३ f. करी । करा : tuend, machend, bewirkend</p><p>कर m.: Hand (zu कृ 8)</p><p>कर m.: Abgabe, Tribut, Steuer (nicht zu कृ, sondern vermutlich Lehnwort aus dem Tamil - தமிழ்)</p><p>क्रिया f.: Handlung, heilige Handlung, Opferhandlung, Zeremonie (zu कृ 8)</p><p>अधि Präverb: über, auf, er-, mit Bezug auf</p><p>गम् +अधि 1 P अधिगच्छति : antreffen, gelangen zu, erlangen</p><p>तनूकृ 8 U तनूकरोति : verringern, schwächen</p><p>दायक ३ f.: दायिका : gebend, schenkend</p><p>नृप m.: &quot;Beschützer der Männer&quot; = König</p><p>प्रणिधान n.: Anwendung, Anstrengung, Aufmerksamkeit gegen, Dienstfertigkeit, Nachdenken, Gelübde</p><p>बाधना f.: Bedrängnis, Plage, Pein</p><p>भार्या f.: &quot;zu Erhaltende&quot; = Gattin</p><p>भावना f.: meditative Entfaltung (zu भू Kausativ)</p><p>मही f.: Erde, Grund und Boden</p><p>लक्षण n.: Merkmal, Kennzeichen, Attribut</p><p>विप्र m.: &quot;Zitterer&quot; = Dichter, Sänger, Priester, Brahmane</p><p>विषय m.: Gebiet, Bereich, Objekt, Sinnesobjekt</p><p>अपवर्ग m.: Ende, Erlösung</p><p>नि Präverb: niederwärts, hinunter, hinein, rückwärts</p><p>वृत् + नि 1 Ā निवर्तते : umkehren, zurückkehren</p><p>सद् 1 P सीदति (!) Pass. सद्यते PPP सन्न : sitzen, sich niederlassen</p><p>सद् + प्र 1 P प्रसीदति : sich setzen, gesetzt werden (im übertragenen Sinn) = abgeklärt, ruhig, heiter werden ; jemandem (Genetiv षष्ठि) gnädig sein</p><p>समाधि m.: innere Sammlung, höchste Aufmerksamkeit, meditative &quot;Versenkung&quot;</p><p>स्वाध्याय m.: &quot;Selbststudium&quot;, Rezitation (besonders des Veda), Vedastudium</p><p>परलौकिक ३ : das Jenseits betreffend, jenseitig</p><p>तनु ३ : schlank</p><p>मध्य ३ : mittlerer; n. Mitte</p><p>पृथु ३ (पृथ्वी) : weit, breit, groß</p><p>श्रोणि । श्रोणी f.: Hüfte</p><p>रक्त ३ : gefärbt, rot</p><p>ओष्ठ m.: Lippe</p><p>असित ३ : dunkel, schwarz</p><p>ईक्ष् 1 Ā ईक्षते Pass. ईक्ष्यते PPP ईक्षित : sehen</p><p>नम् 1 P नमति Pass. नम्यते PPP नत : beugen</p><p>उद् Präverb: auf, hinauf, hinaus, aus, aus-</p><p>नाभि f.: Nabel</p><p>वपुस् n.: Schönheit, Gestalt Körper (Deklination siehe später)</p><p>स्त्री f.: Frau</p><p>स्तन m.: Brust</p><p>दरैद्र ३ : arm</p><p>ऋध् 5 P ऋध्नोति Pass. ऋध्यते PPP ऋद्ध : gedeihen</p><p>ऋध् + सम् : gedeihen; PPP: gelungen, reich</p><p>विचित्र ३ : bunt, verschiedenartig, schön, wunderbar, seltsam</p><p>विधि m.(!): Anordnung, Gesetz, Vorschrift; Schöpfung, Schicksal</p><p>चेष्ट् 1 Ā चेष्तते Pass. चेष्ट्यते PPP चेष्टित : sich regen</p><h2 id="ubung-1" tabindex="-1">Übung 1 <a class="header-anchor" href="#ubung-1" aria-label="Permalink to &quot;Übung 1&quot;">​</a></h2><p>Lösen Sie die folgenden Komposita als Bahuvrīhi und/oder Dvandva und/oder Tatpuruṣa auf alle Ihnen als möglich erscheinenden Arten in Sanskrit auf (Ausnahme: Komposita mit adverbiellem Vorderglied). Übersetzen Sie diese verschieden aufgelösten Komposita ins Deutsche, geben Sie Geschlecht, Fall und Zahl des Gesamtkompositums an.</p><ol><li>इन्द्रशत्रवः</li><li>दुष्कुलायाः</li><li>जातिमात्रस्य</li><li>प्राप्तोदकाः</li><li>सुनीतिभिः</li><li>मृतपुत्रः</li><li>गतपुण्येन</li><li>आर्यरूपम्</li><li>मुक्तासनया</li><li>तद्रूपः</li><li>कृतफलानाम्</li><li>व्याघ्रबलाः</li><li>प्राप्तकाला</li><li>सूरपुत्राम्</li><li>कृतभिषेखः</li><li>शूरबलान्</li><li>वीतमोहः</li><li>द्ण्डहस्तस्य</li><li>गतमात्रम्</li><li>इन्द्रपुत्रा</li><li>तद्गुणाः</li><li>उपल्ब्धसुखैः</li><li>प्राप्तप्रभावः</li><li>तन्मात्राणि</li><li>प्रभूतरूपा</li><li>कृतोपनयनाः</li><li>विगतनयनम्</li><li>बुद्धमार्गेण</li><li>विजयफलान्</li><li>दुर्गमः</li><li>समयकारः</li><li>सम्पन्नरूपाम्</li><li>रूपसम्पन्नाम्</li><li>अपुण्यानाम्</li><li>मृतगृहाणि</li><li>अजनस्य</li><li>तद्देवतैः</li><li>जातपुत्राः</li><li>दुरन्ताभिः</li><li>भूतसर्गेण</li><li>मतिदर्शनम्</li><li>मुक्तहस्ता</li><li>तदन्तः</li><li>जातिमात्रम्</li><li>तज्जयेन</li><li>लब्धधनानाम्</li><li>सुदर्शः</li><li>सकारणः</li><li>तनादयः</li><li>जातमात्राम्</li><li>दुर्जातयः</li><li>हतपुत्रः</li><li>दुरासितम्</li><li>इष्टदेवतया</li><li>कृतपुण्याभिः</li><li>श्रुत्युदितम्</li><li>गतपापैः</li><li>जितारिणा</li><li>जातकोपा</li><li>जातिधर्मः</li><li>तत्प्रभृतयः</li><li>सुदुर्जयः</li><li>जितक्रोधेन</li><li>दुरुपदेशम्</li><li>लब्धलाभा</li><li>बुद्धदासः</li><li>मुक्तबुद्धिः</li><li>यज्ञकालम्</li><li>जितशत्रून्</li><li>शत्रुजितान्</li><li>तत्फलः</li><li>सुगुणा</li><li>जातक्रोधः</li><li>दृष्टमात्रः</li><li>भूतकालः</li><li>सुनेत्राः</li><li>तदादीनाम्</li><li>जातिस्मरणम्</li><li>सफलम्</li><li>अकरुणस्य</li><li>सोढदुःखाः</li></ol><h2 id="ubung-2" tabindex="-1">Übung 2 <a class="header-anchor" href="#ubung-2" aria-label="Permalink to &quot;Übung 2&quot;">​</a></h2><p>A) Übersetzen Sie und lösen Sie die Komposita in Sanskrit auf:</p><p>इन्द्रशत्र्वनार्या देवेन्द्रेण जीयन्ते ॥१॥</p><p>शूरबलक्षत्रिययोधः शूरपुत्रमिच्छति ॥२॥</p><p>सुदुर्गममार्गेण स्वर्गं गम्यते । सुगमस्तु नरकमार्गः ॥३॥</p><p>मृतपुत्रब्राह्मणी रोदिति ॥४॥</p><p>वीतमोहब्राह्मणः सम्पन्नरूपामपि शूद्रां न लुभ्यति ॥५॥</p><p>सुनीतिपुत्रः प्राप्तमतिदर्शनसाधुं गच्छति ॥६॥</p><p>प्राप्तप्रभावक्षत्रिया दृष्टमात्राञ्छत्रून्घ्नन्ति ॥७॥</p><p>जितशत्रुयोधाः शत्रुजितान्मुञ्चन्ति ॥८॥</p><p>कृतोपनयनबालः शिवादिदेवपूजां करोति ॥९॥</p><p>बुद्धगता दुःखादिसत्यानि शृण्वन्ति ॥१०॥</p><p>B) Übersetzen Sie unter Verwendung von Komposita ins Sanskrit:</p><p>1. Ein Kṣatriya, der den Stock nicht in der Hand hält, behütet das Volk nicht.</p><p>2. Kālidāsa und die übrigen Dichter sind die Lehrer im Sanskrit.</p><p>3. Ein Kṣatriya hat seinen Lebensunterhalt durch Waffen.</p><p>4. Auch Śūdrafrauen haben als Dharma Gewaltlosigkeit, Wahrheit, Reinheit, Nicht-Murren, Nicht-Boshaftigkeit und Langmut.</p><h2 id="_20-12-ubersetzungsubung" tabindex="-1">20.12. Übersetzungsübung <a class="header-anchor" href="#_20-12-ubersetzungsubung" aria-label="Permalink to &quot;20.12. Übersetzungsübung&quot;">​</a></h2><p>मैत्रीकरुणामुदितोपेक्षाणां सुखदुःखपुण्यापुण्यविषयाणां भावनतश्चित्तप्रसादनम् ॥योगसूत्र १.३३॥</p><blockquote><p>Erklärung: भाव्नातस् = भावना + Suffix -tas, das ablativische Bedeutung hat. Übersetzen Sie: &quot;aufgrund von ...&quot; oder ähnlich.</p></blockquote><p>तपःस्वाध्यायेश्वरप्रणिधानानि क्रियायोगः ॥योगसूत्र २.१॥<br> समाधिभावनार्थः क्लेशतनूकरणार्थश्च ॥योगसूत्र २.२॥</p><blockquote><p>Erklärung: तपस् n. (Deklination später): Glut, Hitze, Qual ; Askeseglut, Kasteiung</p></blockquote><p><img src="'+p+'" alt=""><br> Abb.: तपस्<br> Buddha als Asket vor seiner erlösenden Einsicht<br> Gandhara, 2./3. Jhdt.<br> [Bildquelle: Wikipedia, GNU FDLicense]</p><p>त्रिविधदुःखात्यन्तनिवृत्तिरत्यनपुरुषार्थः ॥सांख्यसूत्र १.१॥ (Zum Sāṃkhyasystem siehe Basham, Wonder S. 324f.)</p><blockquote><p>Erklärung: त्रिविध ३ : &quot;dreifach&quot;</p></blockquote><p>Definition er Erlösung nach dem Nyāyasystem:</p><blockquote><p>बाधनालक्षणं दुःखम् ॥न्यायसूत्र १.२१॥<br> तदत्यन्तविमोक्षो ऽपवर्गः ॥न्यायसूत्र १.२२॥</p></blockquote><p>Ausspruch der Materialisten nach dem सर्वदर्शनसंग्रह :</p><blockquote><p>न स्वर्गो नापवर्गो वा नैवात्मा पारलौकिकः ।<br> नैव वर्णाश्रमादीनां क्रियाश्च फलदायिकाः ॥</p><p>Erklärung:  अत्मा = Nom.sg. mask. zu आत्मन् m. &quot;Selbst, Seele ; das Absolute, insofern es in einem Individuum realisiert wird&quot;</p></blockquote><p>Ein सुभाषितम् :</p><blockquote><p>देवानां करदा विप्रा<br> विप्राणां करदा नृपाः ।<br> नृपाणां करदा लोका<br> लोकानां करदा मही ॥</p><p>Erläuterung: -da am Ende eines Kompositums: &quot;gebend&quot;</p></blockquote><p><img src="'+m+'" alt=""><br> Abb.: लोकानां करदा महीव्<br> Karnataka<br> [Bildquelle: mattlogelin. -- <a href="http://www.flickr.com/photos/mattlogelin/188758072/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mattlogelin/188758072/</a>. -- Zugriff am 2008-12-11. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p><p>Über Besitzverhältnisse:</p><blockquote><p>भार्या पुत्रश्च दासश्च<br> त्रय एवाधनाः स्मृताः ।<br> यत्ते समधिगच्छन्ति<br> यस्य ते तस्य तद्धनम् ॥मनुस्मृति ८.४१६॥</p><p>Erklärung: त्रयस् = Nom. mask. pl. zu त्रि &quot;drei&quot;</p></blockquote><p>Ein सुभाषितम् über weibliche Schönheit:</p><blockquote><p>तनुमध्यं पृथुश्रोणि<br> रक्तौष्ठमसितेक्षणम् ।<br> नतनाभि वपुः स्त्रीणां<br> कं न हन्त्युन्नतस्तनम् ॥</p><p>Erklärung: alle Formen außer कं und स्त्रीणाम् sind Nom. sg. neut. und beziehen sich auf वपुस्.</p></blockquote><p><img src="'+b+'" alt=""><br> तनुमध्यं पृथुश्रोणि<br> रक्तौष्ठमसितेक्षणम् ।<br> नतनाभि वपुः स्त्रीणां<br> कं न हन्त्युन्नतस्तनम् ॥</p><p>Sanchi = सांची<br> [Bildquelle Wikipedia, Public domain]</p><p>Noch ein सुभाषितम् :</p><blockquote><p>सन्ति पुत्राः सुबहवो<br> दरिद्राणामनिच्छताम् ।<br> नास्ति पुत्रः समृद्धानां<br> विचित्रं विधिचेष्टितम् ॥</p><p>Erklärung: इच्छताम् = gen. Pl. Part Präs. P zu इष् : der wünschenden</p></blockquote>',166)])])}const P=i(c,[["render",g]]);export{B as __pageData,P as default};
